using System.Linq; using System.Data.Entity; using System.Windows; using System.Windows.Controls; using WarehouseManagement.ApplicationData;
namespace WarehouseManagement.Pages { public partial class AdminUsersPage:Page { public AdminUsersPage(){InitializeComponent(); Load();} void Load(){lvUsers.ItemsSource=AppConnect.model01.Users.Include("UserRoles").ToList();} private void btnBack_Click(object s,RoutedEventArgs e){AppFrame.frmMain.GoBack();} private void btnChangeRole_Click(object s,RoutedEventArgs e){if(lvUsers.SelectedItem is Users u){var roles=AppConnect.model01.UserRoles.OrderBy(x=>x.RoleID).ToList(); u.RoleID=roles[(roles.FindIndex(x=>x.RoleID==u.RoleID)+1)%roles.Count].RoleID; AppConnect.model01.SaveChanges(); WarehouseService.Log("Изменение","Users",u.UserID,"Смена роли"); Load();}} private void btnToggleBlock_Click(object s,RoutedEventArgs e){if(lvUsers.SelectedItem is Users u){u.IsBlocked=!u.IsBlocked; AppConnect.model01.SaveChanges(); WarehouseService.Log("Изменение","Users",u.UserID,"Блокировка: "+u.IsBlocked); Load();}}}}
